from .general import GeneralLoRALoader
import torch


class SdxlLoRALoader(GeneralLoRALoader):
    def __init__(self, device="cpu", torch_dtype=torch.float32):
        super().__init__(device=device, torch_dtype=torch_dtype)

    def fuse_lora_to_base_model(self, model: torch.nn.Module, state_dict_lora, alpha=1.0):
        super().fuse_lora_to_base_model(model, state_dict_lora, alpha)
    
    def is_opensource_format(self, state_dict):
        for i in state_dict:
            if i.startswith("lora_unet_"):
                return True
        return False

    def convert_state_dict(self, state_dict, suffix=".weight"):
        if self.is_opensource_format(state_dict):
            state_dict = {i: state_dict[i] for i in state_dict if i.startswith("lora_unet_")}
            state_dict = SdxlLoRAConverter.align_to_diffsynth_format(state_dict)
        return super().convert_state_dict(state_dict, suffix=suffix)


