    @staticmethod
    def align_to_opensource_format(state_dict, alpha=None):
        rename_dict = SdxlLoRAConverter().rename_dict
        state_dict_ = {}
        for name in state_dict:
            if name.endswith(".lora_A.default.weight"):
                name_ = rename_dict[name]
                state_dict_[name_.replace(".lora_down.weight", ".alpha")] = torch.tensor([state_dict[name].shape[0]], dtype=state_dict[name].dtype)[0]
            elif name.endswith(".lora_B.default.weight"):
                name_ = rename_dict[name.replace("lora_B", "lora_A")].replace("lora_down", "lora_up")
            state_dict_[name_] = state_dict[name]
        return state_dict_
    
    @staticmethod
    def align_to_diffsynth_format(state_dict):
        rename_dict = SdxlLoRAConverter().rename_dict
        rename_dict = {rename_dict[i]: i for i in rename_dict}
        state_dict_ = {}
        for name in state_dict:
            if not name.startswith("lora_unet"):
                continue
            if name.endswith(".lora_down.weight"):
                name_ = rename_dict[name]
            elif name.endswith(".lora_up.weight"):
                name_ = rename_dict[name.replace("lora_up", "lora_down")].replace("lora_A", "lora_B")
            elif name.endswith(".alpha"):
                name_ = rename_dict[name.replace(".alpha", ".lora_down.weight")].replace("lora_A.weight", ".alpha")
            state_dict_[name_] = state_dict[name]
        return state_dict_
